chrome.runtime.onInstalled.addListener(()=>{console.log("BugMind AI Extension installed")});chrome.sidePanel.setPanelBehavior({openPanelOnActionClick:!0}).catch(e=>console.error(e));chrome.tabs.onRemoved.addListener(e=>{const s=`bugmind_tab_${e}`;chrome.storage.local.remove([s],()=>{console.log(`Cleaned up storage for tab ${e}`)});try{const t=indexedDB.open("BugMindDB",1);t.onsuccess=r=>{const o=r.target.result;if(o.objectStoreNames.contains("tab_bugs")){const n=o.transaction(["tab_bugs"],"readwrite");n.objectStore("tab_bugs").delete(e),n.oncomplete=()=>console.log(`Cleaned up IndexedDB bugs for tab ${e}`)}o.close()},t.onerror=()=>{}}catch{}});
